# @cctt_verify {"v":2,"sym":"sympy.matrices.normalforms.smith_normal_decomp","kind":"function","src_hash":"b1d30eeda67df82b","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"smith_normal_decomp(m, )","rhs":"return the smith normal decomposition of a matrix `m` over the ring `domain`","over":{"base":"Any"},"name":"smith_normal_decomp_correct","kind":"composition"},"guarantee":"return the smith normal decomposition of a matrix `m` over the ring `domain`","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"to_Matrix","by":"library_axiom"},{"fn":"to_Matrix","by":"library_axiom"},{"fn":"to_Matrix","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"b78e6bc165d8b578"}
def smith_normal_decomp(m, domain=None):
    '''
    Return the Smith Normal Decomposition of a matrix `m` over the ring
    `domain`. This will only work if the ring is a principal ideal domain.

    Examples
    ========

    >>> from sympy import Matrix, ZZ
    >>> from sympy.matrices.normalforms import smith_normal_decomp
    >>> m = Matrix([[12, 6, 4], [3, 9, 6], [2, 16, 14]])
    >>> a, s, t = smith_normal_decomp(m, domain=ZZ)
    >>> assert a == s * m * t
    '''
    dM = _to_domain(m, domain)
    a, s, t = _snd(dM)
    return a.to_Matrix(), s.to_Matrix(), t.to_Matrix()


