# @cctt_verify {"v":2,"sym":"sympy.matrices.normalforms.invariant_factors","kind":"function","src_hash":"fb061bd24a98e3e7","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"invariant_factors(m, )","rhs":"return the tuple of abelian invariants for a matrix `m` (as in the smith-normal form)","over":{"base":"Any"},"name":"invariant_factors_correct"},"guarantee":"return the tuple of abelian invariants for a matrix `m` (as in the smith-normal form)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.matrices.normalforms.invariant_factors_correct","statement":"Path(invariant_factors(x), return the tuple of abelian invariants for a matrix `m` (as in the smith-normal form))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"2c6da904276c15c9"}
def invariant_factors(m, domain=None):
    '''
    Return the tuple of abelian invariants for a matrix `m`
    (as in the Smith-Normal form)

    References
    ==========

    .. [1] https://en.wikipedia.org/wiki/Smith_normal_form#Algorithm
    .. [2] https://web.archive.org/web/20200331143852/https://sierra.nmsu.edu/morandi/notes/SmithNormalForm.pdf

    '''
    dM = _to_domain(m, domain)
    factors = _invf(dM)
    factors = tuple(dM.domain.to_sympy(f) for f in factors)
    # XXX: deprecated.
    if hasattr(m, "ring"):
        if m.ring.is_PolynomialRing:
            K = m.ring
            to_poly = lambda f: Poly(f, K.symbols, domain=K.domain)
            factors = tuple(to_poly(f) for f in factors)
    return factors


